import{_ as e,o as a,c as l,ag as n}from"./chunks/framework.BGD3kWga.js";const c=JSON.parse('{"title":"《林峰系统论 · 产业结构》总览","description":"","frontmatter":{"created":"2026-04-25T00:00:00.000Z","tags":["#林峰系统论/国模块/人/经济","#林峰系统论/总览"]},"headers":[],"relativePath":"01-国模块/01-01-01-02-产业结构总览.md","filePath":"01-国模块/01-01-01-02-产业结构总览.md"}'),r={name:"01-国模块/01-01-01-02-产业结构总览.md"};function d(i,t,s,h,o,g){return a(),l("div",null,[...t[0]||(t[0]=[n(`<h1 id="《林峰系统论-·-产业结构》总览" tabindex="-1">《林峰系统论 · 产业结构》总览 <a class="header-anchor" href="#《林峰系统论-·-产业结构》总览" aria-label="Permalink to &quot;《林峰系统论 · 产业结构》总览&quot;">​</a></h1><h2 id="模块定位" tabindex="-1">模块定位 <a class="header-anchor" href="#模块定位" aria-label="Permalink to &quot;模块定位&quot;">​</a></h2><h3 id="层级位置" tabindex="-1">层级位置 <a class="header-anchor" href="#层级位置" aria-label="Permalink to &quot;层级位置&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">上级</th><th style="text-align:left;">本级</th><th style="text-align:left;">关联模块</th></tr></thead><tbody><tr><td style="text-align:left;">[[01-01-01-经济|经济]]</td><td style="text-align:left;"><strong>产业结构</strong></td><td style="text-align:left;">[[01-01-01-01-宏观经济]]、[[01-01-01-03-个人财富]]</td></tr></tbody></table><h3 id="核心内涵" tabindex="-1">核心内涵 <a class="header-anchor" href="#核心内涵" aria-label="Permalink to &quot;核心内涵&quot;">​</a></h3><p>产业分布与升级转型规律</p><h3 id="主题边界" tabindex="-1">主题边界 <a class="header-anchor" href="#主题边界" aria-label="Permalink to &quot;主题边界&quot;">​</a></h3><ul><li><strong>上限</strong>：宏观经济总量与政策环境</li><li><strong>下限</strong>：企业战略与区域经济</li></ul><hr><h2 id="核心分析框架" tabindex="-1">核心分析框架 <a class="header-anchor" href="#核心分析框架" aria-label="Permalink to &quot;核心分析框架&quot;">​</a></h2><h3 id="底层逻辑" tabindex="-1">底层逻辑 <a class="header-anchor" href="#底层逻辑" aria-label="Permalink to &quot;底层逻辑&quot;">​</a></h3><p>产业结构研究各产业间的比例关系与演进规律，核心在于<strong>产业升级与效率提升</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:center;">产业层级</th><th style="text-align:center;">代表产业</th><th style="text-align:center;">核心特征</th></tr></thead><tbody><tr><td style="text-align:center;"><strong>第一产业</strong></td><td style="text-align:center;">农业</td><td style="text-align:center;">基础性、资源依赖</td></tr><tr><td style="text-align:center;"><strong>第二产业</strong></td><td style="text-align:center;">工业、建筑业</td><td style="text-align:center;">规模化、资本密集</td></tr><tr><td style="text-align:center;"><strong>第三产业</strong></td><td style="text-align:center;">服务业</td><td style="text-align:center;">知识密集、差异化</td></tr></tbody></table><h3 id="主要矛盾" tabindex="-1">主要矛盾 <a class="header-anchor" href="#主要矛盾" aria-label="Permalink to &quot;主要矛盾&quot;">​</a></h3><ol><li><strong>结构优化与就业稳定</strong>：产业转型期的人员安置</li><li><strong>传统产业与新兴产业</strong>：存量调整与增量培育</li><li><strong>区域差异与协调发展</strong>：产业梯度转移</li></ol><h3 id="产业升级路径" tabindex="-1">产业升级路径 <a class="header-anchor" href="#产业升级路径" aria-label="Permalink to &quot;产业升级路径&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>初级阶段：第一产业主导 → 农业经济</span></span>
<span class="line"><span>工业化阶段：第二产业崛起 → 工业经济</span></span>
<span class="line"><span>后工业化阶段：第三产业主导 → 服务经济</span></span>
<span class="line"><span>智能化阶段：三产融合深化 → 数字经济</span></span></code></pre></div><hr><h2 id="笔记索引" tabindex="-1">笔记索引 <a class="header-anchor" href="#笔记索引" aria-label="Permalink to &quot;笔记索引&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">编号</th><th style="text-align:left;">议题</th><th style="text-align:left;">核心论点</th></tr></thead><tbody><tr><td style="text-align:center;">01</td><td style="text-align:left;">产业分类体系</td><td style="text-align:left;">三次产业划分的理论与实践</td></tr><tr><td style="text-align:center;">02</td><td style="text-align:left;">产业升级理论</td><td style="text-align:left;">配第-克拉克定理、库兹涅茨曲线</td></tr><tr><td style="text-align:center;">03</td><td style="text-align:left;">新兴产业培育</td><td style="text-align:left;">战略性新兴产业发展路径</td></tr><tr><td style="text-align:center;">04</td><td style="text-align:left;">传统产业转型</td><td style="text-align:left;">制造业升级改造</td></tr><tr><td style="text-align:center;">05</td><td style="text-align:left;">产业集群发展</td><td style="text-align:left;">产业链集聚与协同效应</td></tr></tbody></table><hr><h2 id="关联分析" tabindex="-1">关联分析 <a class="header-anchor" href="#关联分析" aria-label="Permalink to &quot;关联分析&quot;">​</a></h2><h3 id="与同级模块的横向关联" tabindex="-1">与同级模块的横向关联 <a class="header-anchor" href="#与同级模块的横向关联" aria-label="Permalink to &quot;与同级模块的横向关联&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">关联模块</th><th style="text-align:left;">互动关系</th></tr></thead><tbody><tr><td style="text-align:left;">[[01-01-01-01-宏观经济|宏观经济]]</td><td style="text-align:left;">产业结构是宏观经济的重要侧面</td></tr><tr><td style="text-align:left;">[[01-01-01-03-个人财富|个人财富]]</td><td style="text-align:left;">产业结构决定就业结构与收入分布</td></tr></tbody></table><h3 id="与上下级的纵向关联" tabindex="-1">与上下级的纵向关联 <a class="header-anchor" href="#与上下级的纵向关联" aria-label="Permalink to &quot;与上下级的纵向关联&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">关联方向</th><th style="text-align:left;">关系说明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>↑ 经济</strong></td><td style="text-align:left;">产业结构是经济模块的核心议题</td></tr><tr><td style="text-align:left;"><strong>→ 自然（可持续发展）</strong></td><td style="text-align:left;">产业选择影响资源消耗与环境承载</td></tr><tr><td style="text-align:left;"><strong>→ 科学（技术创新）</strong></td><td style="text-align:left;">技术创新推动产业升级</td></tr><tr><td style="text-align:left;"><strong>→ 事（政策执行）</strong></td><td style="text-align:left;">产业政策需要吏治体系执行</td></tr></tbody></table><hr><h2 id="研究要点" tabindex="-1">研究要点 <a class="header-anchor" href="#研究要点" aria-label="Permalink to &quot;研究要点&quot;">​</a></h2><h3 id="核心问题清单" tabindex="-1">核心问题清单 <a class="header-anchor" href="#核心问题清单" aria-label="Permalink to &quot;核心问题清单&quot;">​</a></h3><ul><li>[ ] 产业结构的评价指标体系</li><li>[ ] 产业升级的驱动因素与路径选择</li><li>[ ] 战略性新兴产业的培育机制</li><li>[ ] 传统产业数字化转型</li><li>[ ] 区域产业协同与梯度转移</li></ul><h3 id="延伸研究方向" tabindex="-1">延伸研究方向 <a class="header-anchor" href="#延伸研究方向" aria-label="Permalink to &quot;延伸研究方向&quot;">​</a></h3><ol><li><strong>产业链安全</strong>：关键环节自主可控</li><li><strong>数字经济与产业融合</strong>：一二三产业数字化转型</li><li><strong>碳中和与产业调整</strong>：绿色产业体系构建</li><li><strong>产业集群竞争力</strong>：世界级产业集群建设</li></ol><hr><h2 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h2><h3 id="文件元信息" tabindex="-1">文件元信息 <a class="header-anchor" href="#文件元信息" aria-label="Permalink to &quot;文件元信息&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">属性</th><th style="text-align:left;">值</th></tr></thead><tbody><tr><td style="text-align:left;">模块名称</td><td style="text-align:left;">产业结构</td></tr><tr><td style="text-align:left;">模块编号</td><td style="text-align:left;">01-01-01-02</td></tr><tr><td style="text-align:left;">上级模块</td><td style="text-align:left;">[[01-01-01-经济]]</td></tr><tr><td style="text-align:left;">创建日期</td><td style="text-align:left;">2026-04-25</td></tr><tr><td style="text-align:left;">文档版本</td><td style="text-align:left;">V1.0</td></tr></tbody></table><h3 id="修订历史" tabindex="-1">修订历史 <a class="header-anchor" href="#修订历史" aria-label="Permalink to &quot;修订历史&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:center;">版本</th><th style="text-align:center;">日期</th><th style="text-align:left;">修订内容</th></tr></thead><tbody><tr><td style="text-align:center;">V1.0</td><td style="text-align:center;">2026-04-25</td><td style="text-align:left;">初始生成总览文档</td></tr></tbody></table>`,38)])])}const y=e(r,[["render",d]]);export{c as __pageData,y as default};
